import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create'); // 'create' or 'manage'
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); 

  // --- EDIT MODAL STATES ---
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
  }, [activeTab, postType, category]);

  // --- UPDATE LOGIC ---
  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      const endpoint = postType === 'job' ? 'jobs' : 'blog';
      // Hum Patch request bhej rahe hain update ke liye
      await axios.patch(`http://localhost:5001/api/admin/${endpoint}/${editData._id}`, editData);
      alert("Updated Successfully!");
      setIsEditing(false);
      fetchItems(); // List refresh
    } catch (err) { alert("Update failed"); }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Kyan aap ise delete karna chahte hain?")) {
      try {
        const endpoint = postType === 'job' ? 'jobs' : 'blog';
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        fetchItems();
        alert("Deleted!");
      } catch (err) { alert("Delete Failed"); }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (postType === 'job') {
        response = await axios.post('http://localhost:5001/api/admin/jobs', formData);
      } else {
        const data = new FormData();
        data.append('category', category);
        data.append('title', formData.title);
        data.append('description', formData.description);
        if (file) data.append('image', file);
        response = await axios.post('http://localhost:5001/api/admin/blog', data);
      }
      if (response.status === 201) {
        alert("Published!");
        setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
        e.target.reset();
      }
    } catch (err) { alert("Error"); }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10">
      {/* SIDEBAR */}
      <div className="w-80 bg-black text-white p-8 fixed h-full">
        <h2 className="text-2xl font-black text-orange-500 mb-10">HUDSON ADMIN</h2>
        <div className="space-y-2">
          <button onClick={() => setActiveTab('create')} className={`w-full text-left p-4 rounded-2xl font-bold ${activeTab === 'create' ? 'bg-orange-600' : 'text-gray-400'}`}>➕ Create New</button>
          <button onClick={() => setActiveTab('manage')} className={`w-full text-left p-4 rounded-2xl font-bold ${activeTab === 'manage' ? 'bg-orange-600' : 'text-gray-400'}`}>⚙️ Manage All</button>
        </div>
        <div className="mt-10 border-t border-gray-800 pt-6">
           <button onClick={() => setPostType('job')} className={`w-full text-left p-2 ${postType === 'job' ? 'text-orange-500' : ''}`}>• Jobs</button>
           <button onClick={() => setPostType('blog')} className={`w-full text-left p-2 ${postType === 'blog' ? 'text-orange-500' : ''}`}>• Blogs</button>
        </div>
      </div>

      {/* MAIN CONTENT */}
      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' ? (
          /* FORM VIEW */
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border">
            <h1 className="text-4xl font-black mb-10 italic">Add Content</h1>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input required className="w-full p-4 bg-gray-50 rounded-xl" placeholder="Title" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />
              {postType === 'blog' ? (
                <textarea rows="4" className="w-full p-4 bg-gray-50 rounded-xl" placeholder="Description" onChange={e => setFormData({...formData, description: e.target.value})} />
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <input className="p-4 bg-gray-50 rounded-xl" placeholder="Loc" onChange={e => setFormData({...formData, loc: e.target.value})} />
                  <input className="p-4 bg-gray-50 rounded-xl" placeholder="Salary" onChange={e => setFormData({...formData, salary: e.target.value})} />
                </div>
              )}
              <button className="w-full bg-black text-white py-5 rounded-xl font-bold">Publish</button>
            </form>
          </div>
        ) : (
          /* MANAGE LIST VIEW */
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border">
            <h1 className="text-4xl font-black mb-10 italic">Manage Content</h1>
            <div className="space-y-4">
              {items.map(item => (
                <div key={item._id} className="flex items-center justify-between p-6 bg-gray-50 rounded-2xl border">
                  <div>
                    <h3 className="font-black text-xl">{item.title}</h3>
                    <p className="text-gray-400 text-xs font-bold uppercase">{item.loc || item.category}</p>
                  </div>
                  <div className="flex gap-2">
                    {/* EDIT BUTTON */}
                    <button 
                      onClick={() => { setEditData(item); setIsEditing(true); }}
                      className="bg-blue-100 text-blue-600 px-6 py-2 rounded-xl font-black text-xs"
                    >
                      EDIT
                    </button>
                    <button onClick={() => handleDelete(item._id)} className="bg-red-50 text-red-500 px-6 py-2 rounded-xl font-black text-xs">DELETE</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* --- EDIT MODAL (POPUP) --- */}
      {isEditing && editData && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-12 relative shadow-2xl">
            <button onClick={() => setIsEditing(false)} className="absolute top-8 right-8 text-2xl font-light">✕</button>
            <h2 className="text-3xl font-black mb-8 italic text-orange-600 underline">Edit Post</h2>

            <form onSubmit={handleUpdate} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Title</label>
                <input required className="w-full p-4 bg-gray-50 rounded-xl font-bold border focus:border-orange-500 outline-none" 
                  value={editData.title} onChange={e => setEditData({...editData, title: e.target.value})} />
              </div>

              {postType === 'blog' ? (
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Description</label>
                  <textarea rows="4" className="w-full p-4 bg-gray-50 rounded-xl font-bold border focus:border-orange-500 outline-none" 
                    value={editData.description} onChange={e => setEditData({...editData, description: e.target.value})} />
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Location</label>
                    <input className="w-full p-4 bg-gray-50 rounded-xl font-bold border focus:border-orange-500 outline-none" 
                      value={editData.loc} onChange={e => setEditData({...editData, loc: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Salary</label>
                    <input className="w-full p-4 bg-gray-50 rounded-xl font-bold border focus:border-orange-500 outline-none" 
                      value={editData.salary} onChange={e => setEditData({...editData, salary: e.target.value})} />
                  </div>
                </div>
              )}

              <button type="submit" className="w-full bg-orange-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-orange-200">
                SAVE CHANGES
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;
